//common define/typedef header used by table-precalculator too


#include <stdint.h>


#define FIXEDPOINT_PREFIX "FIXEDPOINT_"


#define FIXPI FIXED(3.14159) //22.0/7.0 = 3.14285


#define FIXEDPOINT_WORD_BITS 32
#define FIXEDPOINT_WORD_MSB_VALUE ( 1 << (FIXEDPOINT_WORD_BITS-1) )
#define FIXEDPOINT_WORD_SIGNBIT_VALUE (FIXEDPOINT_WORD_MSB_VALUE)
//#define FIXEDPOINT_INTEGER_BITS      16  //the preferred limit to have room (8 bits) for multiplication/etc.
#define FIXEDPOINT_FRACTIONAL_BITS    8  //arithmetic right-sifting negatives is implementation-dependent but GCC supports it, it differs from division in rounding though.
#define FIXEDPOINT_FRACTIONAL_SHIFTS  (FIXEDPOINT_FRACTIONAL_BITS)
#define FIXEDPOINT_FRACTIONAL_RATIO   (1 << FIXEDPOINT_FRACTIONAL_BITS)
#define FIXEDPOINT_FRACTIONAL_RANGE   (FIXEDPOINT_FRACTIONAL_RATIO)
#define FIXEDPOINT_VALUE_1            (FIXEDPOINT_FRACTIONAL_RATIO)
#define FIXEDPOINT_VALUE_MINUS_1      (-FIXEDPOINT_FRACTIONAL_RATIO)
#define FIXEDPOINT_FRACTIONAL_MAX     (FIXEDPOINT_VALUE_1 - 1)
#define FIXEDPOINT_FRACTIONAL_ANDMASK (FIXEDPOINT_FRACTIONAL_MAX)
//#define FIXEDPOINT_FRACTIONAL_SIGNED_ANDMASK (FIXEDPOINT_FRACTIONAL_MAX | FIXEDPOINT_WORD_SIGNBIT_VALUE)

#define FIXED(x) ( (fixed) ( (x) * FIXEDPOINT_FRACTIONAL_RATIO ) )       // + ((x) >= 0 ? +0.5 : -0.5) )


#define FIXEDPOINT_TABLEVALUE_BITS 8
#define FIXEDPOINT_TABLEVALUE_RANGE (1 << FIXEDPOINT_TABLEVALUE_BITS) //values
#define FIXEDPOINT_TABLEVALUE_INTEGER_BITS (FIXEDPOINT_TABLEVALUE_BITS)
#define FIXEDPOINT_TABLEVALUE_MAX (FIXEDPOINT_TABLEVALUE_RANGE - 1)
#define FIXEDPOINT_SQRT_TABLEVALUE_INTEGER_BITS 4
#define FIXEDPOINT_TABLEVALUE_FRACTIONAL_BITS 4
#define FIXEDPOINT_TABLEVALUE_FRACTIONAL_SHIFTS (FIXEDPOINT_TABLEVALUE_FRACTIONAL_BITS)
#define FIXEDPOINT_TABLEVALUE_FRACTIONAL_RANGE (1 << FIXEDPOINT_TABLEVALUE_FRACTIONAL_BITS)
//#define FIXEDPOINT_TABLEVALUE_BITS (FIXEDPOINT_TABLEVALUE_INTEGER_BITS + FIXEDPOINT_TABLEVALUE_FRACTIONAL_BITS)
#define FIXEDPOINT_TABLE_SIZE 256 //entries
#define FIXEDPOINT_SINE_TABLE_SIZE 360 //entries


typedef int32_t  s32;
typedef uint32_t u32;
typedef s32      fixed;
typedef u32      ufixed;
typedef uint8_t  u8;
typedef uint8_t  byte;
typedef uint16_t word;
typedef uint32_t dword;


